export class ApiClientBase{constructor({moduleName,supabase,demoDataFn=null}){this.moduleName=moduleName;this.supabase=supabase;this.demoDataFn=demoDataFn;this.cache=new Map();this.cacheExpiry=60000;}async load(cacheKey,fetchFn){const cached=this.cache.get(cacheKey);if(cached&&Date.now()-cached.timestamp<this.cacheExpiry){return cached.data;}try{const data=await fetchFn();this.cache.set(cacheKey,{data,timestamp: Date.now()});return data;}catch(error){if(this.demoDataFn){return this.demoDataFn();}throw error;}}invalidate(cacheKey){this.cache.delete(cacheKey);}clearCache(){this.cache.clear();}$(id){return document.getElementById(id);}setText(id,text){const el=this.$(id);if(el){el.textContent=String(text);}}setHtml(id,html){const el=this.$(id);if(el){el.innerHTML=html;}}bind(bindings){Object.entries(bindings).forEach(([id,value])=>{this.setText(id,value);});}}export function onReady(initFn){if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initFn);}else{initFn();}}export function renderTable(items,rowFn,containerId){const container=document.getElementById(containerId);if(!container)return;if(!items||items.length===0){container.innerHTML='<tr><td colspan="5" class="text-muted">No data</td></tr>';return;}container.innerHTML=items.map(rowFn).join('');}export function renderList(items,itemFn,containerId){const container=document.getElementById(containerId);if(!container)return;if(!items||items.length===0){container.innerHTML='<div class="text-muted">No items</div>';return;}container.innerHTML=items.map(itemFn).join('');}export function statusBadge(status,colorMap){const colors=colorMap[status]||{bg: '#eee',color: '#333'};const label=status?.toUpperCase()||'N/A';return `<span style="padding: 4px 12px;border-radius: 999px;font-size: 12px;background: ${colors.bg};color: ${colors.color}">${label}</span>`;}export function formatNumberSafe(num){if(!num)return '0';if(num>=1000000)return(num/1000000).toFixed(1)+'M';if(num>=1000)return(num/1000).toFixed(1)+'K';return num.toLocaleString('vi-VN');}export const ACTIVITY_TYPE_COLORS={lead:{color: 'var(--primary-cyan)',label: 'Lead'},deal:{color: 'var(--accent-lime)',label: 'Deal'},invoice:{color: 'var(--secondary-purple)',label: 'Invoice'},campaign:{color: '#FF0055',label: 'Campaign'},project:{color: '#FFAA00',label: 'Project'}};export function renderActivities(activities,containerId='live-activity-list'){const container=document.getElementById(containerId);if(!container)return;if(!activities||activities.length===0){container.innerHTML='<div class="text-muted" style="padding:10px;">No recent activities</div>';return;}container.innerHTML=activities.map(act=>{const typeInfo=ACTIVITY_TYPE_COLORS[act.entity_type]||{color: '#ccc',label: 'Activity'};return `<div class="live-activity-item"><div style="width: 8px;height: 8px;background: ${typeInfo.color};border-radius: 50%;box-shadow: 0 0 10px ${typeInfo.color};"></div><div><div class="title-small" style="font-weight: 600;">${act.action||typeInfo.label}</div><div class="body-small text-muted">${act.description||''}• ${new Date(act.created_at).toLocaleTimeString('vi-VN')}</div></div></div>`;}).join('');}export function renderChart(chartId,chartType,data){if(!window.MekongAdmin||!MekongAdmin.DashboardCharts){return;}const chartFn=MekongAdmin.DashboardCharts[`${chartType}Chart`];if(typeof chartFn==='function'){chartFn(chartId,data);}}export{formatCurrencyVN,formatCurrency,formatCurrencyShort}from './format-utils.js';